import jwt from "jsonwebtoken";
var secret = "ssdfsfsdfsdfsfsfsdfgswrwer";
var createUserAuth = async (payload) => {
  const { password, email, name } = payload;
  const existingUser = await prisma.user.findUnique({
    where: { email }
  });
  if (existingUser) {
    throw new Error("User already exists");
  }
  const hashedPass = await bcrypt.hash(password, 8);
  const user = await prisma.user.create({
    data: {
      name,
      email,
      password: hashedPass
    }
  });
  const token = jwt.sign(
    {
      id: user.id,
      name: user.name,
      email: user.email,
      role: user.role
    },
    secret,
    { expiresIn: "7d" }
  );
  return {
    token,
    user
  };
};
var loginUserAuth = async (payload) => {
  const user = await prisma.user.findUnique({
    where: {
      email: payload.email
    }
  });
  if (!user) {
    throw new Error("User not found");
  }
  const verifypass = await bcrypt.compare(payload.password, user.password);
  if (!verifypass) {
    throw new Error("Invalid credential");
  }
  const userData = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role
  };
  const token = jwt.sign(userData, secret, { expiresIn: "7d" });
  return {
    token,
    user
  };
};
var AuthService = {
  // Add service methods here
  createUserAuth,
  loginUserAuth
};

// src/modules/auth/auth.controller.ts
var registerUser = async (req, res) => {
  try {
    const result = await AuthService.createUserAuth(req.body);
    res.status(201).json({
      success: true,
      message: "User registered successfully",
      token: result.token,
      data: result.user
    });
  } catch (error) {
    res.status(400).json({
      success: false,
      message: "User registration failed",
      error: error.message
    });
  }
};
var loginUser = async (req, res) => {
  try {
    const result = await AuthService.loginUserAuth(req.body);
    const { password, ...userWithoutPassword } = result.user;
    res.cookie("token", result.token, {
      httpOnly: true,
      sameSite: "none",
      // 🔥 change this
      secure: true,
      maxAge: 7 * 24 * 60 * 60 * 1e3
    });
    res.status(200).json({
      success: true,
      message: "Login successful",
      token: result.token,
      data: userWithoutPassword
    });
  } catch (error) {
    res.status(401).json({
      success: false,
      message: error.message
    });
  }
};
var getMe = async (req, res) => {
  try {
    const user = req.user;
    res.status(200).json({
      success: true,
      data: user
    });
  } catch (error) {
    res.status(401).json({
      success: false,
      message: "Unauthorized"
    });
  }
};
var AuthController = {
  registerUser,
  loginUser,
  getMe
};

// src/middlewares/authMiddleware.ts
import jwt2 from "jsonwebtoken";
var authMiddleware = async (req, res, next) => {
  try {
    console.log("Cookies:", req.cookies);
    const token = await req.cookies?.token;
    console.log("token:", token);
    if (!token) {
      throw new Error("Unauthorized");
    }
    const decoded = jwt2.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    console.log("user:", req.user);
    next();
  } catch (error) {
    res.status(401).json({
      success: false,
      message: "Unauthorized"
    });
  }
};

// src/modules/auth/auth.router.ts
var router = express.Router();
router.post("/register", AuthController.registerUser);
router.post("/login", AuthController.loginUser);
router.get("/me", authMiddleware, AuthController.getMe);
