var createIdea = async (payload, userId) => {
  console.log("userId:", userId);
  const idea = await prisma.idea.create({
    data: {
      ...payload,
      authorId: userId
    }
  });
  return idea;
};
var getAllIdeas = async (query) => {
  const { search, categoryId, status } = query;
  const ideas = await prisma.idea.findMany({
    where: {
      AND: [
        search ? {
          OR: [
            { title: { contains: search, mode: "insensitive" } },
            { description: { contains: search, mode: "insensitive" } },
            // 🌿 NEW: search by category name
            {
              category: {
                name: {
                  contains: search,
                  mode: "insensitive"
                }
              }
            }
          ]
        } : {},
        // 🌿 Filter by selected category
        categoryId ? { categoryId } : {},
        status ? { status } : {}
      ]
    },
    include: {
      author: {
        select: { id: true, name: true }
      },
      category: true,
      votes: true
    },
    orderBy: {
      createdAt: "desc"
    }
  });
  return ideas;
};
var getIdeaById = async (id, userId) => {
  const idea = await prisma.idea.findUnique({
    where: { id },
    include: {
      author: true,
      category: true,
      comments: {
        include: {
          replies: true
        }
      },
      votes: true,
      purchases: true
    }
  });
  if (!idea) {
    throw new Error("Idea not found");
  }
  if (idea.isPaid) {
    const purchased = idea.purchases.find(
      (p) => p.userId === userId
    );
    if (!purchased) {
      return {
        id: idea.id,
        title: idea.title,
        price: idea.price,
        message: "This is a paid idea. Please purchase to view details."
      };
    }
  }
  return idea;
};
var getIdeasByUserId = async (userId) => {
  const ideas = await prisma.idea.findMany({
    where: {
      authorId: userId
    },
    include: {
      author: {
        select: {
          id: true,
          name: true,
          email: true
        }
      },
      category: true,
      votes: true
    },
    orderBy: {
      createdAt: "desc"
    }
  });
  return ideas;
};
var updateIdea = async (id, userId, payload) => {
  const idea = await prisma.idea.findUnique({
    where: { id }
  });
  if (!idea) throw new Error("Idea not found");
  if (idea.authorId !== userId) {
    throw new Error("Unauthorized");
  }
  if (idea.status === "APPROVED") {
    throw new Error("Approved ideas cannot be edited");
  }
  const updated = await prisma.idea.update({
    where: { id },
    data: payload
  });
  return updated;
};
var deleteIdea = async (id, userId) => {
  const idea = await prisma.idea.findUnique({
    where: { id }
  });
  if (!idea) throw new Error("Idea not found");
  if (idea.authorId !== userId) {
    throw new Error("Unauthorized");
  }
  const deleted = await prisma.idea.delete({
    where: { id }
  });
  return deleted;
};
var updateIdeaStatus = async (id, status) => {
  const idea = await prisma.idea.update({
    where: { id },
    data: { status }
  });
  return idea;
};
var ideaService = {
  createIdea,
  getAllIdeas,
  getIdeaById,
  getIdeasByUserId,
  updateIdea,
  deleteIdea,
  updateIdeaStatus
};

