// src/modules/vote/vote.service.ts
var voteIdea = async (userId, ideaId, type) => {
  const existing = await prisma.vote.findUnique({
    where: {
      userId_ideaId: {
        userId,
        ideaId
      }
    }
  });
  if (existing && existing.type === type) {
    await prisma.vote.delete({
      where: {
        userId_ideaId: { userId, ideaId }
      }
    });
    return { message: "Vote removed" };
  }
  if (existing) {
    return prisma.vote.update({
      where: {
        userId_ideaId: { userId, ideaId }
      },
      data: { type }
    });
  }
  return prisma.vote.create({
    data: {
      userId,
      ideaId,
      type
    }
  });
};
var removeVote = async (userId, ideaId) => {
  return prisma.vote.delete({
    where: {
      userId_ideaId: {
        userId,
        ideaId
      }
    }
  });
};
var getVoteSummary = async (ideaId) => {
  const votes = await prisma.vote.findMany({
    where: { ideaId }
  });
  const upVotes = votes.filter((v) => v.type === "UP").length;
  const downVotes = votes.filter((v) => v.type === "DOWN").length;
  return {
    upVotes,
    downVotes,
    score: upVotes - downVotes
  };
};
var voteService = {
  voteIdea,
  removeVote,
  getVoteSummary
};

